(()=>{"use strict";const Conditions=Object.freeze({INCLUDES:"includes",EQUALS:"equals"});const defaultOpts={successRate:100,unlock:false,priority:100,condition:Conditions.INCLUDES};setup.Conditions=Conditions;window.Conditions=window.Conditions||Conditions;class Recipe{constructor(id,ingredients={},opts=clone(defaultOpts),tags=[]){this.id=id;if(typeof ingredients!=="object"||typeof opts!=="object"){throw new Error("Invalid recipe definition")}this.ingredients=ingredients;Object.assign(this,Object.assign({},defaultOpts,opts));this._tags=tags instanceof Array?tags:typeof tags==="string"?[tags]:[]}get name(){return this.displayName||this.id}set name(val){this.displayName=val}get tags(){return this._tags}hasTag(tag){return this._tags.includes(tag)}hasAllTags(tags){return this._tags.includesAll(tags)}hasAnyTags(tags){return this._tags.includesAny(tags)}validate(ingredients){switch(this.condition){case Conditions.EQUALS:return this.equals(ingredients);case Conditions.INCLUDES:return this.includes(ingredients);default:throw new TypeError(`Invalid condition type: ${this.condition}`)}}calculate(input){return Object.entries(this.ingredients).reduce(((min,[ingredient,require])=>{const available=input[ingredient];return Math.min(min,Math.floor(available/require))}),Infinity)}multiply(servings){if(typeof servings!=="number"||servings<=0){throw new Error("Invalid number of servings")}const required={};for(const ingredient in this.ingredients){required[ingredient]=this.ingredients[ingredient]*servings}return required}includes(ingredients){if(Object.keys(ingredients).length<Object.keys(this.ingredients).length){return false}for(const ingredient in this.ingredients){if(!ingredients[ingredient]||ingredients[ingredient]<this.ingredients[ingredient]){return false}}return true}cook(){if(this.successRate===100){return true}const number=randomInt(1,100);if(this.successRate>=number){return true}return false}equals(ingredients){if(Object.keys(ingredients).length!==Object.keys(this.ingredients).length){return false}for(const ingredient in this.ingredients){if(!ingredients[ingredient]||ingredients[ingredient]!==this.ingredients[ingredient]){return false}}return true}}setup.Recipe=Recipe;window.Recipe=window.Recipe||Recipe})();(()=>{"use strict";const convertToArray=input=>{const array=[];for(const[key,value]of Object.entries(input)){array.push(key,value)}return array};class RecipeBook{constructor(ct,recipes=new Map,invs=[]){if(!(recipes instanceof Map)){throw new Error('Expected "recipes" to be an instance of Map')}if(!Array.isArray(invs)){throw new Error('Expected "invs" to be an array')}this.invs=invs;this.ct=ct;this.recipes=recipes;this._recipes=RecipeBook.sort(recipes)}has(id){return this.recipes.has(id)}hasItems(input){const obj=State.getVar(this.ct);for(const[key,required]of Object.entries(input)){const actualCount=obj.count(key);if(actualCount<required){return false}}return true}drop(input){const obj=State.getVar(this.ct);obj.drop(...convertToArray(input))}update(){this._recipes=RecipeBook.sort(this.recipes)}filter(){const tags=[].slice.call(arguments).flat(Infinity);const result=[];for(const recipe of this._recipes){if(recipe.hasAllTags(tags)){result.push(recipe)}}return result}searchIndex(priority){let low=0;let high=this._recipes.length-1;while(low<=high){const mid=Math.floor((low+high)/2);if(this._recipes[mid].priority===priority){return mid}else if(this._recipes[mid].priority<priority){low=mid+1}else{high=mid-1}}return low}insert(id,ingredients,opts,tags){const recipe=this.set(id,ingredients,opts,tags);const index=this.searchIndex(recipe.priority);this._recipes.splice(index,0,recipe)}set(id,ingredients,opts,tags){const recipe=new Recipe(id,ingredients,opts,tags);this.recipes.set(id,recipe);return recipe}cook(input,servings=1){let recipe=this.match(input);let result={id:"",success:true,unlock:true,exist:true,servings:1,message:""};if(recipe===undefined){result.success=false;result.unlock=false;result.exist=false;result.message="配方不存在"}else if(!recipe.unlock&&typeof input==="string"){result.id=recipe.name;result.success=false;result.unlock=false;result.message="配方未解锁"}else if(typeof input==="string"){result.id=recipe.name;const required=recipe.multiply(servings);if(this.hasItems(required)){this.drop(required);result.servings=servings;result.message="制作成功"}else{result.servings=0;result.success=false;result.message="缺少材料"}}else{result.id=recipe.id;result.success=recipe.cook();input.length=0;if(result.success){result.servings=recipe.calculate(input);result.message="制作成功";recipe.unlock=true}else{result.servings=0;result.message="制作失败"}}return result}cookSave(inv,input,servings=1){const result=this.cook(input,servings);if(result.success){RecipeBook.pickup(inv,result.id,result.servings)}return result}match(input){if(typeof input==="object"&&input!==null){for(const recipe of this._recipes){if(!(recipe instanceof Recipe)){throw new Error(`Invalid Recipe: ${recipe}`)}if(recipe.validate(input)){return recipe}}}else if(typeof input==="string"){const recipe=this.recipes.get(input);if(recipe===undefined){return undefined}return recipe}else{throw new Error(`Invalid argument: ${input}`)}return undefined}static sort(recipes){const defaultPriority=100;const recipeArr=Array.from(recipes.values());let counts={};recipeArr.forEach((recipe=>{const priority=recipe.priority!==undefined?recipe.priority:defaultPriority;counts[priority]=(counts[priority]||0)+1}));const priorities=Object.keys(counts).map(Number).sort(((a,b)=>a-b));let accumulatedCounts={};let cumulativeSum=0;priorities.forEach((priority=>{accumulatedCounts[priority]=cumulativeSum;cumulativeSum+=counts[priority]}));let arr=Array(recipeArr.length);for(let i=recipeArr.length-1;i>=0;i--){const recipe=recipeArr[i];const priority=recipe.priority!==undefined?recipe.priority:defaultPriority;let position=accumulatedCounts[priority];arr[position]=recipe;accumulatedCounts[priority]++}return arr}static pickup(inv,...item){if(!(inv instanceof Inventory)){throw new Error("Invalid inventory")}return inv.pickup(...item)}}State.variables.crafting_table=State.variables.crafting_table||new Inventory;setup.RecipeBook=setup.RecipeBook||new RecipeBook("$crafting_table");window.RecipeBook=window.RecipeBook||setup.RecipeBook})();(()=>{Macro.add("cook",{tags:null,handler(){if(this.args.length<1){return this.error("Not enough arguments provided. At least two arguments are required.")}const items=this.args[0];if(!(typeof items==="object"||typeof items==="string")||items===null){return this.error("Expected an object or a string, but received: "+typeof items)}let result;if(this.args.length>=2){const inv=this.args[1];if(!inv||!(inv instanceof Inventory)){return this.error("Expected an instance of Inventory, but received: "+typeof inv)}result=RecipeBook.cookSave(inv,items,parseInt(this.args[2])||1)}else{result=RecipeBook.cook(items)}WikiVars({result:result},this)}})})();
